import logo from './logo.svg';
// import './App.css';
import React from 'react';
import Hello from './hello.js';

function App() {
  const name = 'react';
  const style = {
    background : 'pink',
    color : '#fff',
    fontSize : '22px'
  }
  return (
    <div>
      <Hello />
      <div style = {style}>{name}</div>
    </div>
  );
}

export default App;
